transcript.content:
[
  {
    "biasType": "Opinion Statements Presented as Fact",
    "biasedText": "\"What I think is essential to keep in mind here is that if we're going to trust the federal government, how can we trust the federal government to do an objective, unbiassed investigation, without prejudice, when at the beginning of that investigation they have already announced exactly what they saw -- what they think happened.\"",
    "explanation": "Sen. Smith's statement is presented as a reasoned assessment, but it is rooted in her personal skepticism and assumes the federal government's investigation cannot be objective. This opinion is presented as if it is an established fact."
  },
  {
    "biasType": "Unsubstantiated Claims",
    "biasedText": "\"I think what we are seeing here is the federal government -- [Department of Homeland Security Secretary] Kristi Noem, Vice President [JD] Vance, [President] Donald Trump -- attempting to cover up what happened here in the Twin Cities, and I don't think that people here and around the country are believing it,\"",
    "explanation": "The assertion that the named officials are 'attempting to cover up' the incident is a serious claim offered without concrete evidence or attribution beyond Smith's perspective."
  },
  {
    "biasType": "Sensationalism/Emotionalism",
    "biasedText": "\"And, you know, we will not give in. We will not sort of cave in to the fear and the chaos that they are trying to create, they are creating, but we will meet that with unity and with peace.\"",
    "explanation": "The language 'cave in to the fear and the chaos that they are trying to create, they are creating' is emotionally charged and paints the administration as sowing widespread chaos and fear, which heightens the story's emotional impact."
  },
  {
    "biasType": "Mind Reading",
    "biasedText": "\"the Trump administration wants to foment chaos and division and fear and even violence.\"",
    "explanation": "Smith attributes motivations and desires to the Trump administration ('wants to foment chaos...') without direct evidence of intent, presuming to know their internal motivations."
  },
  {
    "biasType": "Omission of Source Attribution",
    "biasedText": "\"The FBI is investigating the shooting, but Minnesota officials said that the federal government has cut them out, blocking state agencies from accessing case material.\"",
    "explanation": "The article states that Minnesota officials claim to have been cut out of the investigation but fails to attribute this claim to a specific individual, document, or official statement."
  }
]

